/* ---------- Cost Scenarios ---------- */
function costScenarios(city, mult, cd) {
  const budget = Math.round(4000 * mult / 50) * 50;
  const mid = Math.round(15000 * mult / 50) * 50;
  const prem = Math.round(35000 * mult / 50) * 50;

  const budgetBody = `${cd.nativePlantPalettePara.split(". ")[0]}. ${cd.lawnMaterialPara.split(". ")[0]}.`;
  const midBody = `${cd.hardscapeStylePara.split(". ")[0]}. ${cd.irrigationRegsPara.split(". ")[0]}.`;
  const premBody = `${cd.turfAndXeriscapeRebatesPara.split(". ")[0]}. ${cd.stormwaterPara.split(". ")[0]}.`;

  function card(label, title, total, body, color) {
    return `
<div class="fp-scenario-card" style="border-top:4px solid ${color};">
<h3>${label}</h3>
<p class="fp-scenario-material">${title}</p>
<p class="fp-scenario-total">${fmtK(total)}</p>
<p class="fp-scenario-detail">${body}</p>
</div>`;
  }

  return `
<section class="section fp-section">
<h2>${city} Landscape Project Scenarios</h2>
<div class="fp-scenario-grid">
${card("Budget", `Basic ${city} lawn and garden`, budget, budgetBody, "#22c55e")}
${card("Mid-Range", `${city} hardscape plus planting`, mid, midBody, "#3b82f6")}
${card("Premium", `${city} full landscape design`, prem, premBody, "#8b5cf6")}
</div>
</section>`;
}

